import { readFile, readdir, writeFile } from "node:fs/promises";
import path from "node:path";
import process from "node:process";
import { fileURLToPath } from "node:url";

const dashboardRoot = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const generatedMarker =
  "<!-- Generated by Vite and dashboard/scripts/finalize-third-party-licenses.mjs. Do not edit. -->";

function formatEntry({ identifier, label, source, text, version }) {
  const versionText = version === undefined ? "" : ` - ${version}`;
  const sourceText = source === undefined ? "" : `Source: ${source}\n\n`;
  return `## ${label}${versionText} (${identifier})\n\n${sourceText}${text.trim()}\n`;
}

async function packageLicense(packageName) {
  const packageDirectory = path.join(dashboardRoot, "node_modules", ...packageName.split("/"));
  const metadata = JSON.parse(await readFile(path.join(packageDirectory, "package.json"), "utf8"));
  const entries = await readdir(packageDirectory);
  const licenseFile = entries
    .filter((entry) => /^licen[cs]e(?:\.|$)/i.test(entry))
    .sort((left, right) => left.localeCompare(right))[0];

  if (typeof metadata.version !== "string" || typeof metadata.license !== "string") {
    throw new Error(`${packageName} must declare string version and license fields`);
  }
  if (licenseFile === undefined) {
    throw new Error(`${packageName} does not contain a license file`);
  }

  return {
    identifier: metadata.license,
    label: packageName,
    text: await readFile(path.join(packageDirectory, licenseFile), "utf8"),
    version: metadata.version,
  };
}

async function filesBelow(directory, suffix) {
  const files = [];
  for (const entry of await readdir(directory, { withFileTypes: true })) {
    const entryPath = path.join(directory, entry.name);
    if (entry.isDirectory()) {
      files.push(...(await filesBelow(entryPath, suffix)));
    } else if (entry.isFile() && entry.name.endsWith(suffix)) {
      files.push(entryPath);
    }
  }
  return files;
}

function packageNameFromImport(specifier) {
  if (
    specifier.startsWith(".") ||
    specifier.startsWith("/") ||
    /^[a-z][a-z+.-]*:/i.test(specifier)
  ) {
    return undefined;
  }
  const parts = specifier.split("/");
  return specifier.startsWith("@") ? parts.slice(0, 2).join("/") : parts[0];
}

async function importedCssPackages() {
  const packageNames = new Set();
  for (const cssPath of await filesBelow(path.join(dashboardRoot, "src"), ".css")) {
    const css = await readFile(cssPath, "utf8");
    for (const match of css.matchAll(/@import\s+(?:url\(\s*)?["']([^"']+)["']/g)) {
      const packageName = packageNameFromImport(match[1]);
      if (packageName !== undefined) {
        packageNames.add(packageName);
      }
    }
  }
  return [...packageNames].sort((left, right) => left.localeCompare(right));
}

async function supplementalLicenses() {
  const cssLicenses = await Promise.all(
    (await importedCssPackages()).map((packageName) => packageLicense(packageName)),
  );
  return [
    {
      identifier: "MIT",
      label: "shadcn/ui registry source",
      source: "https://github.com/shadcn-ui/ui",
      text: await readFile(
        path.join(dashboardRoot, "third_party", "shadcn-ui.LICENSE"),
        "utf8",
      ),
    },
    ...cssLicenses,
  ];
}

async function main() {
  const outputArgument = process.argv[2];
  if (outputArgument === undefined) {
    throw new Error("usage: finalize-third-party-licenses.mjs <vite-output-directory>");
  }

  const outputDirectory = path.resolve(dashboardRoot, outputArgument);
  const noticePath = path.join(outputDirectory, "THIRD_PARTY_LICENSES.md");
  let notice = await readFile(noticePath, "utf8");
  if (!notice.startsWith("# Licenses\n")) {
    throw new Error(`${noticePath} is not the license inventory emitted by Vite`);
  }

  const additions = [];
  for (const entry of await supplementalLicenses()) {
    const headingPrefix = `## ${entry.label}`;
    if (!notice.split("\n").some((line) => line.startsWith(headingPrefix))) {
      additions.push(formatEntry(entry));
    }
  }

  if (!notice.includes(generatedMarker)) {
    notice = `${generatedMarker}\n\n${notice}`;
  }
  if (additions.length > 0) {
    notice = `${notice.trimEnd()}\n\n${additions.join("\n")}`;
  }
  await writeFile(noticePath, `${notice.trimEnd()}\n`, "utf8");
}

await main();
